solution:
def count_islands(grid):
    if not grid or not grid[0]:
        return 0
    rows, cols = len(grid), len(grid[0])
    seen = set()
    count = 0
    for r0 in range(rows):
        for c0 in range(cols):
            if grid[r0][c0] != 1 or (r0, c0) in seen:
                continue
            count += 1
            stack = [(r0, c0)]
            seen.add((r0, c0))
            while stack:
                r, c = stack.pop()
                for dr, dc in ((1,0),(-1,0),(0,1),(0,-1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < rows and 0 <= nc < cols and \
                       grid[nr][nc] == 1 and (nr, nc) not in seen:
                        seen.add((nr, nc))
                        stack.append((nr, nc))
    return count

def split_csv_line(line):
    fields = []
    buf = []
    i = 0
    n = len(line)
    while True:
        if i < n and line[i] == '"':
            i += 1
            closed = False
            while i < n:
                ch = line[i]
                if ch == '"':
                    if i + 1 < n and line[i + 1] == '"':
                        buf.append('"')
                        i += 2
                    else:
                        i += 1
                        closed = True
                        break
                else:
                    buf.append(ch)
                    i += 1
            if not closed:
                raise ValueError("unterminated quoted field")
            if i < n and line[i] != ',':
                raise ValueError("unexpected character after closing quote")
        else:
            while i < n and line[i] != ',':
                if line[i] == '"':
                    raise ValueError("quote inside unquoted field")
                buf.append(line[i])
                i += 1
        fields.append(''.join(buf))
        buf = []
        if i < n:
            i += 1
        else:
            break
    return fields

