def merge_tallies(a, b):
    def check(v):
        if isinstance(v, bool) or not isinstance(v, int):
            raise ValueError("count must be int, not bool/other")

    for v in a.values():
        check(v)
    for v in b.values():
        check(v)
    out = {}
    for k, v in a.items():
        total = v + b.get(k, 0)
        if total != 0:
            out[k] = total
    for k, v in b.items():
        if k not in a and v != 0:
            out[k] = v
    return out

def apply_edits(items, ops):
    def norm(i, n, upper):
        j = i + n if i < 0 else i
        if j < 0 or j > upper:
            raise IndexError("index out of range")
        return j

    out = list(items)
    for op in ops:
        if not isinstance(op, tuple) or not op:
            raise ValueError("malformed op")
        name = op[0]
        if name == "insert":
            if len(op) != 3:
                raise ValueError("malformed op")
            j = norm(op[1], len(out), len(out))
            out.insert(j, op[2])
        elif name == "delete":
            if len(op) != 2:
                raise ValueError("malformed op")
            j = norm(op[1], len(out), len(out) - 1)
            del out[j]
        elif name == "replace":
            if len(op) != 3:
                raise ValueError("malformed op")
            j = norm(op[1], len(out), len(out) - 1)
            out[j] = op[2]
        else:
            raise ValueError("unknown op")
    return out

