    def check_int(x):
        if isinstance(x, bool) or not isinstance(x, int):
            raise ValueError("expected a non-bool int")

    def is_leap(y):
        return y % 4 == 0 and (y % 100 != 0 or y % 400 == 0)

    def days_in(y, m):
        if m == 2:
            return 29 if is_leap(y) else 28
        return 31 if m in (1, 3, 5, 7, 8, 10, 12) else 30

