def edit(commands):
    def parse_count(arg):
        if arg == "" or any(c not in "0123456789" for c in arg):
            raise ValueError("bad count")
        n = int(arg)
        if n == 0:
            raise ValueError("bad count")
        return n

    buf = ""
    cur = 0
    undo_stack = []
    for cmd in commands:
        if cmd == "undo":
            if undo_stack:
                buf, cur = undo_stack.pop()
            continue
        sep = cmd.find(" ")
        if sep == -1:
            raise ValueError("bad command")
        verb, arg = cmd[:sep], cmd[sep + 1:]
        if verb == "type":
            if arg == "":
                raise ValueError("bad command")
            undo_stack.append((buf, cur))
            buf = buf[:cur] + arg + buf[cur:]
            cur += len(arg)
        elif verb == "left":
            cur = max(0, cur - parse_count(arg))
        elif verb == "right":
            cur = min(len(buf), cur + parse_count(arg))
        elif verb == "backspace":
            k = min(parse_count(arg), cur)
            if k > 0:
                undo_stack.append((buf, cur))
                buf = buf[:cur - k] + buf[cur:]
                cur -= k
        else:
            raise ValueError("bad command")
    return (buf, cur)

def decode_frame(frame):
    if len(frame) % 2 != 0:
        raise ValueError("odd length")
    hexdigits = set("0123456789abcdefABCDEF")
    if any(c not in hexdigits for c in frame):
        raise ValueError("not hex")
    if len(frame) < 6:
        raise ValueError("truncated")
    data = [int(frame[i:i + 2], 16) for i in range(0, len(frame), 2)]
    if data[0] != 0xA5:
        raise ValueError("bad header")
    n = data[1]
    if len(data) != 3 + n:
        raise ValueError("length mismatch")
    payload = data[2:2 + n]
    if (data[0] + n + sum(payload) + data[-1]) % 256 != 0:
        raise ValueError("bad checksum")
    return payload

