def turtle(prog):
    dirs = "NESW"
    dx = {"N": 0, "E": 1, "S": 0, "W": -1}
    dy = {"N": 1, "E": 0, "S": -1, "W": 0}
    x = y = h = 0
    i = 0
    n = len(prog)
    while i < n:
        c = prog[i]
        count = 1
        if c.isdigit():
            j = i
            while j < n and prog[j].isdigit():
                j += 1
            if prog[i] == "0":
                raise ValueError("bad count")
            if j >= n:
                raise ValueError("dangling count")
            count = int(prog[i:j])
            i = j
            c = prog[i]
        if c == "L":
            h = (h - count) % 4
        elif c == "R":
            h = (h + count) % 4
        elif c == "F":
            d = dirs[h]
            x += dx[d] * count
            y += dy[d] * count
        elif c == "B":
            d = dirs[h]
            x -= dx[d] * count
            y -= dy[d] * count
        else:
            raise ValueError("bad command")
        i += 1
    return (x, y, dirs[h])

def grant_requests(capacity, events):
    if not isinstance(capacity, int) or isinstance(capacity, bool) or capacity < 1:
        raise ValueError("bad capacity")
    tokens = capacity
    last = None
    out = []
    for ev in events:
        if type(ev) is not tuple or len(ev) != 2:
            raise ValueError("bad event")
        ts, amt = ev
        for v in (ts, amt):
            if not isinstance(v, int) or isinstance(v, bool):
                raise ValueError("bad event")
        if amt < 1:
            raise ValueError("bad event")
        if last is not None and ts < last:
            raise ValueError("time warp")
        if last is not None:
            tokens = min(capacity, tokens + (ts - last))
        last = ts
        if tokens >= amt:
            tokens -= amt
            out.append(True)
        else:
            out.append(False)
    return out

