def stopwatch(events):
    ops = ("start", "stop", "lap", "reset")
    total = 0
    laps = []
    running = False
    started = 0
    last = None
    for ev in events:
        if type(ev) is not tuple or len(ev) != 2:
            raise ValueError("bad event")
        ts, op = ev
        if not isinstance(ts, int) or isinstance(ts, bool) or op not in ops:
            raise ValueError("bad event")
        if last is not None and ts <= last:
            raise ValueError("time warp")
        last = ts
        if op == "start":
            if running:
                raise ValueError("already running")
            running = True
            started = ts
        elif op == "stop":
            if not running:
                raise ValueError("not running")
            total += ts - started
            running = False
        elif op == "lap":
            if not running:
                raise ValueError("not running")
            laps.append(total + (ts - started))
        else:
            if running:
                raise ValueError("still running")
            total = 0
            laps = []
    return (total, laps)

