            raise ValueError("bad expr")
        pos += 1

    def factor():
        c = peek()
        if c == "!":
            eat("!")
            return not factor()
        if c == "(":
            eat("(")
            v = disjunction()
            eat(")")
            return v
        if c == "T":
            eat("T")
            return True
        if c == "F":
            eat("F")
            return False
        raise ValueError("bad expr")

    def conjunction():
        v = factor()
        while peek() == "&":
            eat("&")
            rhs = factor()
            v = v and rhs
        return v

    def disjunction():
        v = conjunction()
        while peek() == "|":
            eat("|")
            rhs = conjunction()
            v = v or rhs
