def parse_a1(ref):
    if not isinstance(ref, str) or ref == "":
        raise ValueError("bad ref")
    i, n = 0, len(ref)
    while i < n and "A" <= ref[i] <= "Z":
        i += 1
    if i == 0 or i == n:
        raise ValueError("bad ref")
    letters = ref[:i]
    digits = ref[i:]
    if not digits.isascii() or not digits.isdigit():
        raise ValueError("bad ref")
    if len(digits) > 1 and digits[0] == "0":
        raise ValueError("bad ref")
    row = int(digits)
    if row < 1:
        raise ValueError("bad ref")
    col = 0
    for ch in letters:
        col = col * 26 + (ord(ch) - 64)
    return (row, col)

def has_cycle(nxt):
    for v in nxt:
        if not isinstance(v, int) or isinstance(v, bool):
            raise ValueError("bad link")
        if v < -1 or v >= len(nxt):
            raise ValueError("bad link")
    if not nxt:
        return False
    seen = set()
    cur = 0
    while cur != -1:
        if cur in seen:
            return True
        seen.add(cur)
        cur = nxt[cur]
    return False

def tour_length(points):
    for p in points:
        if type(p) is not tuple or len(p) != 2:
            raise ValueError("bad point")
        for v in p:
            if not isinstance(v, int) or isinstance(v, bool):
                raise ValueError("bad point")
    total = 0
    for i in range(1, len(points)):
        ax, ay = points[i - 1]
        bx, by = points[i]
        total += abs(bx - ax) + abs(by - ay)
    return total

