def parse_kv(s):
    if not isinstance(s, str):
        raise ValueError("bad input")
    if s == "":
        return []
    out = []
    seen = set()
    for item in s.split(";"):
        if "=" not in item:
            raise ValueError("bad item")
        key, _, val = item.partition("=")
        if key == "":
            raise ValueError("bad item")
        for ch in key:
            if not (ch.isascii() and (ch.isalnum() or ch == "_")):
                raise ValueError("bad item")
        if "=" in val:
            raise ValueError("bad item")
        if key in seen:
            raise ValueError("duplicate key")
        seen.add(key)
        out.append((key, val))
    return out

def rotate(items, k):
    if not isinstance(items, list):
        raise ValueError("bad input")
    if not isinstance(k, int) or isinstance(k, bool):
        raise ValueError("bad shift")
    n = len(items)
    if n == 0:
        return []
    k %= n
    if k == 0:
        return list(items)
    return items[-k:] + items[:-k]

def group_anagrams(words):
    groups = {}
    for w in words:
        if not isinstance(w, str):
            raise ValueError("bad item")
        key = "".join(sorted(w))
        groups.setdefault(key, []).append(w)
    result = [sorted(g) for g in groups.values()]
    result.sort(key=lambda g: g[0])
    return result

def stock_spans(prices):
    for p in prices:
        if isinstance(p, bool) or not isinstance(p, (int, float)):
            raise ValueError("bad price")
    spans = []
    stack = []
    for i, p in enumerate(prices):
        while stack and prices[stack[-1]] <= p:
            stack.pop()
        span = i + 1 if not stack else i - stack[-1]
        spans.append(span)
        stack.append(i)
    return spans

def perm_rank(perm):
    if not isinstance(perm, list):
        raise ValueError("bad input")
    for x in perm:
        if not isinstance(x, int) or isinstance(x, bool):
            raise ValueError("bad element")
    n = len(perm)
    if sorted(perm) != list(range(n)):
        raise ValueError("not a permutation")
    rank = 0
    for i in range(n):
        smaller = sum(1 for y in perm[i + 1:] if y < perm[i])
        f = 1
        for m in range(2, n - i):
            f *= m
        rank += smaller * f
    return rank

def gray_rank(bits):
    if not isinstance(bits, str) or bits == "":
        raise ValueError("bad code")
    for c in bits:
        if c not in "01":
            raise ValueError("bad code")
    g = int(bits, 2)
    i = 0
    while g:
        i ^= g
        g >>= 1
    return i

def kth_combination(n, k, r):
    if not isinstance(n, int) or isinstance(n, bool) or n < 0:
        raise ValueError("bad n")
    if not isinstance(k, int) or isinstance(k, bool) or k < 0 or k > n:
        raise ValueError("bad k")

    def comb(a, b):
        if b < 0 or b > a:
            return 0
        b = min(b, a - b)
        num = 1
        for j in range(b):
            num = num * (a - j) // (j + 1)
        return num

    total = comb(n, k)
    if not isinstance(r, int) or isinstance(r, bool) or r < 0 or r >= total:
        raise ValueError("bad rank")
    out = []
    x = 0
    remaining = k
    rr = r
    while remaining > 0:
        c = comb(n - x - 1, remaining - 1)
        if rr < c:
            out.append(x)
            remaining -= 1
        else:
            rr -= c
        x += 1
    return out

def look_and_say(seed, steps):
    if not isinstance(seed, str) or seed == "":
        raise ValueError("bad seed")
    for c in seed:
        if not ("0" <= c <= "9"):
            raise ValueError("bad seed")
    if not isinstance(steps, int) or isinstance(steps, bool) or steps < 0:
        raise ValueError("bad steps")
    cur = seed
    for _ in range(steps):
        out = []
        i = 0
        while i < len(cur):
            j = i
            while j < len(cur) and cur[j] == cur[i]:
                j += 1
            if j - i > 9:
                raise ValueError("run overflow")
            out.append(str(j - i))
            out.append(cur[i])
            i = j
        cur = "".join(out)
    return cur

