def longest_digit_run(n):
    if not isinstance(n, int) or isinstance(n, bool) or n < 0:
        raise ValueError("bad number")
    s = str(n)
    best_start, best_len = 0, 1
    i = 0
    while i < len(s):
        j = i
        while j < len(s) and s[j] == s[i]:
            j += 1
        if j - i > best_len:
            best_start, best_len = i, j - i
        i = j
    return (best_start, best_len, int(s[best_start]))

def collatz_trace(n, limit):
    if not isinstance(n, int) or isinstance(n, bool) or n < 1:
        raise ValueError("bad start")
    if not isinstance(limit, int) or isinstance(limit, bool) or limit < 0:
        raise ValueError("bad limit")
    trace = [n]
    cur = n
    steps = 0
    while cur != 1:
        if steps == limit:
            raise RuntimeError("limit exceeded")
        cur = cur // 2 if cur % 2 == 0 else 3 * cur + 1
        trace.append(cur)
        steps += 1
    return trace

def knight_moves(n, start, goal):
    if not isinstance(n, int) or isinstance(n, bool) or n < 1:
        raise ValueError("bad board")
    for cell in (start, goal):
        if type(cell) is not tuple or len(cell) != 2:
            raise ValueError("bad cell")
        for v in cell:
            if not isinstance(v, int) or isinstance(v, bool):
                raise ValueError("bad cell")
            if v < 0 or v >= n:
                raise ValueError("bad cell")
    if start == goal:
        return 0
    deltas = ((1, 2), (2, 1), (2, -1), (1, -2),
              (-1, -2), (-2, -1), (-2, 1), (-1, 2))
    dist = {start: 0}
    queue = [start]
    head = 0
    while head < len(queue):
        r, c = queue[head]
        head += 1
        d = dist[(r, c)]
        for dr, dc in deltas:
            nr, nc = r + dr, c + dc
            if 0 <= nr < n and 0 <= nc < n and (nr, nc) not in dist:
                if (nr, nc) == goal:
                    return d + 1
                dist[(nr, nc)] = d + 1
                queue.append((nr, nc))
    return -1

def path_steps(grid):
    if not isinstance(grid, list) or not grid:
        raise ValueError("bad grid")
    for row in grid:
        if not isinstance(row, list) or not row:
            raise ValueError("bad grid")
    width = len(grid[0])
    for row in grid:
        if len(row) != width:
            raise ValueError("ragged")
    for row in grid:
        for cell in row:
            if not isinstance(cell, int) or isinstance(cell, bool) or cell not in (0, 1):
                raise ValueError("bad cell")
    rows, cols = len(grid), width
    if grid[0][0] == 1 or grid[rows - 1][cols - 1] == 1:
        return -1
    if rows == 1 and cols == 1:
        return 0
    dist = [[-1] * cols for _ in range(rows)]
    dist[0][0] = 0
    queue = [(0, 0)]
    head = 0
    while head < len(queue):
        r, c = queue[head]
        head += 1
        for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == 0 and dist[nr][nc] == -1:
                dist[nr][nc] = dist[r][c] + 1
                if nr == rows - 1 and nc == cols - 1:
                    return dist[nr][nc]
                queue.append((nr, nc))
    return -1

def component_count(n, edges):
    if not isinstance(n, int) or isinstance(n, bool) or n < 0:
        raise ValueError("bad n")
    if not isinstance(edges, list):
        raise ValueError("bad edges")
    for e in edges:
        if type(e) is not tuple or len(e) != 2:
            raise ValueError("bad edge")
        for v in e:
            if not isinstance(v, int) or isinstance(v, bool) or v < 0 or v >= n:
                raise ValueError("bad edge")
    parent = list(range(n))

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    count = n
    for a, b in edges:
        ra, rb = find(a), find(b)
        if ra != rb:
            parent[ra] = rb
            count -= 1
    return count

def is_bipartite(adj):
    if not isinstance(adj, list):
        raise ValueError("bad adjacency")
    for row in adj:
        if not isinstance(row, list):
            raise ValueError("bad adjacency")
    n = len(adj)
    for row in adj:
        for v in row:
            if not isinstance(v, int) or isinstance(v, bool) or v < 0 or v >= n:
                raise ValueError("bad neighbor")
    for i in range(n):
        for j in adj[i]:
            if i not in adj[j]:
                raise ValueError("not symmetric")
    color = [None] * n
    for s in range(n):
        if color[s] is not None:
            continue
        color[s] = 0
        queue = [s]
        head = 0
        while head < len(queue):
            u = queue[head]
            head += 1
            for v in adj[u]:
                if color[v] is None:
                    color[v] = 1 - color[u]
                    queue.append(v)
                elif color[v] == color[u]:
                    return False
    return True

def portal_moves(n, portals, start, goal):
    if not isinstance(n, int) or isinstance(n, bool) or n < 1:
        raise ValueError("bad n")
    for cell in (start, goal):
        if not isinstance(cell, int) or isinstance(cell, bool) or cell < 0 or cell >= n:
            raise ValueError("bad cell")
    if not isinstance(portals, list):
        raise ValueError("bad portal")
    jump = {}
    for p in portals:
        if type(p) is not tuple or len(p) != 2:
            raise ValueError("bad portal")
        for v in p:
            if not isinstance(v, int) or isinstance(v, bool) or v < 0 or v >= n:
                raise ValueError("bad portal")
        if p[0] in jump:
            raise ValueError("duplicate portal")
        jump[p[0]] = p[1]
    if start == goal:
        return 0
    dist = [-1] * n
    dist[start] = 0
    queue = [start]
    head = 0
    while head < len(queue):
        u = queue[head]
        head += 1
        nxts = []
        if u - 1 >= 0:
            nxts.append(u - 1)
        if u + 1 < n:
            nxts.append(u + 1)
        if u in jump:
            nxts.append(jump[u])
        for v in nxts:
            if dist[v] == -1:
                dist[v] = dist[u] + 1
                if v == goal:
                    return dist[v]
                queue.append(v)
    return dist[goal]

def spread_radius(grid):
    if not isinstance(grid, list) or not grid:
        raise ValueError("bad grid")
    for row in grid:
        if not isinstance(row, str) or row == "":
            raise ValueError("bad grid")
    width = len(grid[0])
    for row in grid:
        if len(row) != width:
            raise ValueError("ragged")
    for row in grid:
        for ch in row:
            if ch not in "S.#":
                raise ValueError("bad cell")
    rows, cols = len(grid), width
    dist = [[-1] * cols for _ in range(rows)]
    queue = []
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == "S":
                dist[r][c] = 0
                queue.append((r, c))
    if not queue:
        raise ValueError("no source")
    head = 0
    while head < len(queue):
        r, c = queue[head]
        head += 1
        for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] != "#" and dist[nr][nc] == -1:
                dist[nr][nc] = dist[r][c] + 1
                queue.append((nr, nc))
    best = 0
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == ".":
                if dist[r][c] == -1:
                    return -1
                if dist[r][c] > best:
                    best = dist[r][c]
    return best

