def lru_trace(capacity, ops):
    if not isinstance(capacity, int) or isinstance(capacity, bool) or capacity < 1:
        raise ValueError("bad capacity")
    cache = {}
    out = []
    for op in ops:
        if type(op) is not tuple or len(op) < 1:
            raise ValueError("bad op")
        if op[0] == "get" and len(op) == 2:
            key = op[1]
            if key in cache:
                val = cache.pop(key)
                cache[key] = val
                out.append(val)
            else:
                out.append(None)
        elif op[0] == "put" and len(op) == 3:
            key, val = op[1], op[2]
            if key in cache:
                cache.pop(key)
            elif len(cache) >= capacity:
                cache.pop(next(iter(cache)))
            cache[key] = val
        else:
            raise ValueError("bad op")
    return out

