def min_stack(ops):
    if not isinstance(ops, list):
        raise ValueError("bad ops")
    stack = []
    out = []
    for op in ops:
        if type(op) is not tuple or len(op) < 1:
            raise ValueError("bad op")
        if (op[0] == "push" and len(op) == 2 and isinstance(op[1], int)
                and not isinstance(op[1], bool)):
            stack.append(op[1])
        elif op == ("pop",):
            if not stack:
                raise ValueError("empty stack")
            out.append(stack.pop())
        elif op == ("top",):
            if not stack:
                raise ValueError("empty stack")
            out.append(stack[-1])
        elif op == ("min",):
            if not stack:
                raise ValueError("empty stack")
            out.append(min(stack))
        else:
            raise ValueError("bad op")
    return out

