def bank_ledger(ops):
    balance = 0
    out = []
    for op in ops:
        if (type(op) is not tuple or len(op) != 2
                or op[0] not in ("deposit", "withdraw")):
            raise ValueError("bad op")
        kind, amount = op
        if not isinstance(amount, int) or isinstance(amount, bool) or amount < 1:
            raise ValueError("bad amount")
        if kind == "deposit":
            balance += amount
        else:
