solution:
def reserve_trace(stock, ops):
    if not isinstance(stock, dict):
        raise ValueError("bad stock")
    for key, val in stock.items():
        if not isinstance(key, str):
            raise ValueError("bad stock")
        if not isinstance(val, int) or isinstance(val, bool) or val < 0:
            raise ValueError("bad stock")
    reserved = {}
    for op in ops:
        if (type(op) is not tuple or len(op) != 3
                or op[0] not in ("reserve", "cancel")):
            raise ValueError("bad op")
        kind, item, qty = op
        if not isinstance(qty, int) or isinstance(qty, bool) or qty < 1:
            raise ValueError("bad qty")
        if item not in stock:
            raise ValueError("unknown item")
        cur = reserved.get(item, 0)
        if kind == "reserve":
            if qty > stock[item] - cur:
                raise ValueError("not enough " + item)
            reserved[item] = cur + qty
        else:
            if qty > cur:
                raise ValueError("over-cancel")
            reserved[item] = cur - qty
    return sorted((it, n) for it, n in reserved.items() if n > 0)

