solution:
def split_url(url):
    if not isinstance(url, str):
        raise ValueError("bad url")
    idx = url.find("://")
    if idx == -1:
        raise ValueError("no scheme")
    scheme = url[:idx]
    if scheme == "" or not ("a" <= scheme[0] <= "z"):
        raise ValueError("bad scheme")
    for ch in scheme[1:]:
        if not ("a" <= ch <= "z" or "0" <= ch <= "9" or ch in "+-."):
            raise ValueError("bad scheme")
    rest = url[idx + 3:]
    end = len(rest)
    for i, ch in enumerate(rest):
        if ch in "/?":
            end = i
            break
    authority = rest[:end]
    tail = rest[end:]
    host, sep, port_s = authority.partition(":")
    if host == "":
        raise ValueError("bad host")
    for ch in host:
        if not ("a" <= ch <= "z" or "0" <= ch <= "9" or ch in "-."):
            raise ValueError("bad host")
    if sep:
        if port_s == "" or not all("0" <= c <= "9" for c in port_s):
            raise ValueError("bad port")
        if len(port_s) > 1 and port_s[0] == "0":
            raise ValueError("bad port")
        port = int(port_s)
        if port > 65535:
            raise ValueError("bad port")
    else:
        port = None
    if tail.startswith("/"):
        q = tail.find("?")
        if q == -1:
            path, query = tail, None
        else:
            path, query = tail[:q], tail[q + 1:]
    elif tail.startswith("?"):
        path, query = "/", tail[1:]
    else:
        path, query = "/", None
    return (scheme, host, port, path, query)

def qp_decode(s):
    if not isinstance(s, str):
        raise ValueError("bad input")
    out = []
    i, n = 0, len(s)
    while i < n:
        ch = s[i]
        if ch != "=":
            out.append(ch)
            i += 1
            continue
        if i + 1 < n and s[i + 1] == "\n":
            i += 2
            continue
        if i + 2 < n and s[i + 1] == "\r" and s[i + 2] == "\n":
            i += 3
            continue
        if i + 2 < n:
            h = s[i + 1:i + 3]
            if all(c in "0123456789ABCDEF" for c in h):
                out.append(chr(int(h, 16)))
                i += 3
                continue
        raise ValueError("bad escape")
    return "".join(out)

