solution:
def parse_ini(text):
    if not isinstance(text, str):
        raise ValueError("bad input")
    result = {}
    current = None
    for raw in text.split("\n"):
        line = raw.strip(" \t")
        if line == "" or line[0] in ";#":
            continue
        if line[0] == "[":
            if not line.endswith("]"):
                raise ValueError("bad section")
            name = line[1:-1]
            if name == "" or not all(
                    "a" <= c <= "z" or "A" <= c <= "Z"
                    or "0" <= c <= "9" or c == "_" for c in name):
                raise ValueError("bad section")
            if name in result:
                raise ValueError("duplicate section")
            result[name] = {}
            current = name
            continue
        if "=" not in line:
            raise ValueError("bad line")
        key, _, val = line.partition("=")
        key = key.strip(" \t")
        val = val.strip(" \t")
        if key == "" or not all(
                "a" <= c <= "z" or "A" <= c <= "Z"
                or "0" <= c <= "9" or c == "_" for c in key):
            raise ValueError("bad line")
        if current is None:
            raise ValueError("no section")
        if key in result[current]:
            raise ValueError("duplicate key")
        result[current][key] = val
    return result

def diff_ops(a, b):
    if not isinstance(a, list) or not isinstance(b, list):
        raise ValueError("bad input")
    for lst in (a, b):
        for x in lst:
            if not isinstance(x, str):
                raise ValueError("bad input")
    n, m = len(a), len(b)
    L = [[0] * (m + 1) for _ in range(n + 1)]
    for i in range(n - 1, -1, -1):
        for j in range(m - 1, -1, -1):
            if a[i] == b[j]:
                L[i][j] = L[i + 1][j + 1] + 1
            else:
                L[i][j] = max(L[i + 1][j], L[i][j + 1])
    ops = []
    i = j = 0
    while i < n or j < m:
        if i < n and j < m and a[i] == b[j]:
            tag, item = "equal", a[i]
            i += 1
            j += 1
        elif j >= m or (i < n and L[i + 1][j] >= L[i][j + 1]):
            tag, item = "delete", a[i]
            i += 1
        else:
            tag, item = "insert", b[j]
            j += 1
        if ops and ops[-1][0] == tag:
            ops[-1][1].append(item)
        else:
            ops.append((tag, [item]))
    return ops

def fletcher16(data):
    if isinstance(data, str):
        byts = []
        for ch in data:
            if ord(ch) > 127:
                raise ValueError("bad char")
            byts.append(ord(ch))
    elif isinstance(data, list):
        for x in data:
            if not isinstance(x, int) or isinstance(x, bool) or x < 0 or x > 255:
                raise ValueError("bad byte")
        byts = data
    else:
        raise ValueError("bad input")
    s1 = s2 = 0
    for byte in byts:
        s1 = (s1 + byte) % 255
        s2 = (s2 + s1) % 255
    return s2 * 256 + s1

