solution:
def outline_number(lines):
    if not isinstance(lines, list):
        raise ValueError("bad input")
    for ln in lines:
        if not isinstance(ln, str):
            raise ValueError("bad input")
    counters = [0] * 6
    prev_level = 0
    out = []
    for ln in lines:
        if not ln.startswith("#"):
            continue
        i = 0
        while i < len(ln) and ln[i] == "#":
            i += 1
        if i > 6 or i >= len(ln) or ln[i] != " ":
            raise ValueError("bad header")
        title = ln[i + 1:]
        if title == "" or title[0] == " ":
            raise ValueError("bad header")
        level = i
        if level > prev_level + 1:
            raise ValueError("bad nesting")
        counters[level - 1] += 1
        for d in range(level, 6):
            counters[d] = 0
        out.append(".".join(str(counters[k]) for k in range(level)) + " " + title)
        prev_level = level
    return out
